const rows = $input.all().map(i => i.json);
const thresholds = [50, 75, 90, 100];
const alerts = [];

for (const row of rows) {
  const pct = Number(row.usage_percent);
  for (const threshold of thresholds) {
    if (pct >= threshold) {
      alerts.push({
        json: {
          organization_id: row.organization_id,
          org_name: row.org_name,
          dimension: row.dimension,
          threshold_percent: threshold,
          usage_percent: pct,
          used: row.used,
          total_available: row.total_available,
          bolt_on_remaining: row.bolt_on_remaining,
          overage: row.overage,
          overage_rate_zar: row.overage_rate_zar,
          billing_period: row.current_period_start
        }
      });
    }
  }
}

if (alerts.length === 0) {
  return [{ json: { no_alerts: true } }];
}
return alerts;

// Build WhatsApp alert message based on threshold
const data = $input.first().json;
if (!data.id) return []; // No new alert (already sent)

const dim = data.dimension.replace(/_/g, ' ');
const pct = $('Calculate Thresholds').item.json.threshold_percent;
const used = $('Calculate Thresholds').item.json.used;
const total = $('Calculate Thresholds').item.json.total_available;
const orgName = $('Calculate Thresholds').item.json.org_name;
const boltOn = $('Calculate Thresholds').item.json.bolt_on_remaining;

let message = '';
if (pct === 50) {
  message = `Hi ${orgName}, your ${dim} usage is at 50% (${used}/${total}). You're on track!`;
} else if (pct === 75) {
  message = `Heads up ${orgName}! Your ${dim} usage is at 75% (${used}/${total}). Top up at your dashboard to avoid overage.`;
} else if (pct === 90) {
  message = `${orgName}, you've used 90% of your ${dim} (${used}/${total}). Top up now to avoid overage charges.`;
} else if (pct === 100 && boltOn > 0) {
  message = `${orgName}, you've used all your plan ${dim} but still have ${boltOn} bolt-on credits. No overage yet!`;
} else if (pct === 100) {
  message = `${orgName}, you've reached your ${dim} limit (${used}/${total}). Extra usage will be charged at overage rates. Top up at your dashboard.`;
}

return [{ json: { message, organization_id: data.organization_id, threshold: pct, dimension: data.dimension } }];
